import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"基础内功","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/武学基础/基础内功.md","filePath":"4.资源分区/6.技艺及称号/武技类/武学基础/基础内功.md"}'),p={name:"4.资源分区/6.技艺及称号/武技类/武学基础/基础内功.md"};function d(_,e,l,i,c,h){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"基础内功",tabindex:"-1"},[n("基础内功 "),a("a",{class:"header-anchor",href:"#基础内功","aria-label":'Permalink to "基础内功"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),o('<h1 id="基础内功-1" tabindex="-1">基础内功 <a class="header-anchor" href="#基础内功-1" aria-label="Permalink to &quot;基础内功&quot;">​</a></h1><p>基础内功<br> D+500<br> 注：此技艺遵循【武学总纲】<br> 注：此技艺视为奠基内功的下位资源。<br> 我该承认，即使是宗师眼中基础中的基础，对未涉及武道的普通人来说还是过于高深，为普及武法，我再著此《奠基之基》，望此世，武道兴隆。</p><p>气海开辟：引神识而牵精气，牵精气而铸气海，习此功者将开启内力能量池。</p><p>此后，修习者将得到内力修行之法，每经历一场影片获得一缕内力，也可称之为内功修为，能助修习者练就：</p><p>*强健体魄：修习者的内力贯通全身，使其体魄更为强大，每消耗两点内功修为可提升一点生命上限。<br> *磐石之心：修习者的内力勾连脑域，使其心神更为强大，每消耗两点内功修为可提升一点意志上限。<br> *再生之机：修习者的内功修为更上一层，滋润体魄，增长五年寿命，此功效需消耗一点内功修为。<br> *内功夯实：修习者的内力再次夯实，内力能量池上限增加三点，此功效需消耗一点内功修为。</p><p>此内功为奠基法之基，不擅推动武技运转，故除为修习者之武技提供修习者本身的内力属性的加成外，不再提供额外加成。</p><p>修习此功者，在经历一场影片之后，可无条件转修奠基内功，保留通过其所获得的加成。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',9)])])}const f=r(p,[["render",d]]);export{m as __pageData,f as default};
